    def _sort_palette(self, sort_palette):
        """
        Returns a copy of this "P" mode image with its palette colors
        reordered, and the pixel data remapped to match.

        :param sort_palette: Either ``"luminance"`` or ``"rgb"``.
        :returns: A new :py:class:`~PIL.Image.Image` object.
        """
        channels = len(self.palette.mode)
        palette = self.palette.palette
        colors = [
            tuple(palette[i : i + channels])
            for i in range(0, len(palette), channels)
        ]

        if sort_palette == "luminance":
            def sort_key(color):
                r, g, b = color[:3]
                return r * 299 + g * 587 + b * 114

        else:
            def sort_key(color):
                return color

        order = sorted(range(len(colors)), key=lambda i: sort_key(colors[i]))
        return self.remap_palette(order)

